/**
 * Authentication Routes
 *
 * REST endpoints for user authentication and session management.
 * Implements JWT-based authentication per spec 005.2.
 *
 * Endpoints:
 * - POST /auth/login - Authenticate user and obtain tokens
 * - POST /auth/refresh - Refresh access token
 * - POST /auth/logout - Invalidate session
 *
 * @see specs/005-api.md Section 5.2
 */

import { Hono } from 'hono';
import {
  success,
  error,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getAuthService,
  type LoginRequest,
  type RefreshRequest,
} from '../../services/auth';
import { validateLoginRequest } from '../../lib/schemas';
import {
  AuthenticationError,
  TokenExpiredError,
  InvalidTokenError,
  isMmsError,
} from '../../lib/errors';

// Singleton service instance
let authService: ReturnType<typeof getAuthService> | null = null;

function getService(): ReturnType<typeof getAuthService> {
  if (!authService) {
    authService = getAuthService();
  }
  return authService;
}

export const authRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * POST /auth/login
 *
 * Authenticate user with email and password.
 * Returns access token, refresh token, and user information.
 */
authRoutes.post('/auth/login', async (c) => {
  const service = getService();
  const requestId = getRequestId(c);

  try {
    // Parse request body
    const body = await c.req.json();

    // Validate login request
    const validation = validateLoginRequest(body);
    if (!validation.valid) {
      return c.json(
        error(
          ErrorCodes.VALIDATION_ERROR,
          'Invalid login request',
          requestId,
          { errors: validation.errors }
        ),
        400 as const
      );
    }

    // Get client info for session tracking
    const ipAddress = c.req.header('x-forwarded-for')?.split(',')[0]?.trim() ||
                      c.req.header('x-real-ip') ||
                      'unknown';
    const userAgent = c.req.header('user-agent') || 'unknown';

    // Perform login
    const loginRequest: LoginRequest = {
      email: body.email,
      password: body.password,
      ipAddress,
      userAgent,
    };

    const result = await service.login(loginRequest);

    return c.json(
      success(result, {
        timing: { durationMs: getRequestDuration(c) },
      })
    );
  } catch (err) {
    if (err instanceof AuthenticationError) {
      return c.json(
        error(ErrorCodes.UNAUTHORIZED, err.message, requestId),
        401 as const
      );
    }

    if (isMmsError(err)) {
      return c.json(
        error(err.code, err.message, requestId),
        err.statusCode as 400 | 401 | 403 | 404 | 409 | 422 | 500 | 502 | 503 | 504
      );
    }

    throw err;
  }
});

/**
 * POST /auth/refresh
 *
 * Refresh access token using refresh token.
 * Implements token rotation for security.
 */
authRoutes.post('/auth/refresh', async (c) => {
  const service = getService();
  const requestId = getRequestId(c);

  try {
    // Parse request body
    const body = await c.req.json();

    // Validate refresh token is provided
    if (!body.refreshToken || typeof body.refreshToken !== 'string') {
      return c.json(
        error(
          ErrorCodes.VALIDATION_ERROR,
          'Refresh token is required',
          requestId
        ),
        400 as const
      );
    }

    // Get client info
    const ipAddress = c.req.header('x-forwarded-for')?.split(',')[0]?.trim() ||
                      c.req.header('x-real-ip') ||
                      'unknown';
    const userAgent = c.req.header('user-agent') || 'unknown';

    // Perform token refresh
    const refreshRequest: RefreshRequest = {
      refreshToken: body.refreshToken,
      ipAddress,
      userAgent,
    };

    const result = await service.refreshToken(refreshRequest);

    return c.json(
      success(result, {
        timing: { durationMs: getRequestDuration(c) },
      })
    );
  } catch (err) {
    if (err instanceof TokenExpiredError) {
      return c.json(
        error(ErrorCodes.UNAUTHORIZED, 'Refresh token has expired', requestId),
        401 as const
      );
    }

    if (err instanceof InvalidTokenError) {
      return c.json(
        error(ErrorCodes.UNAUTHORIZED, err.message, requestId),
        401 as const
      );
    }

    if (isMmsError(err)) {
      return c.json(
        error(err.code, err.message, requestId),
        err.statusCode as 400 | 401 | 403 | 404 | 409 | 422 | 500 | 502 | 503 | 504
      );
    }

    throw err;
  }
});

/**
 * POST /auth/logout
 *
 * Invalidate current session.
 * Requires Authorization header with Bearer token.
 */
authRoutes.post('/auth/logout', async (c) => {
  const service = getService();
  const requestId = getRequestId(c);

  try {
    // Extract token from Authorization header
    const authHeader = c.req.header('authorization');
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return c.json(
        error(
          ErrorCodes.UNAUTHORIZED,
          'Authorization header with Bearer token is required',
          requestId
        ),
        401 as const
      );
    }

    const token = authHeader.substring(7); // Remove 'Bearer ' prefix

    // Perform logout
    await service.logout(token);

    return c.json(
      success({ message: 'Logged out successfully' }, {
        timing: { durationMs: getRequestDuration(c) },
      })
    );
  } catch (err) {
    if (err instanceof InvalidTokenError) {
      return c.json(
        error(ErrorCodes.UNAUTHORIZED, err.message, requestId),
        401 as const
      );
    }

    if (isMmsError(err)) {
      return c.json(
        error(err.code, err.message, requestId),
        err.statusCode as 400 | 401 | 403 | 404 | 409 | 422 | 500 | 502 | 503 | 504
      );
    }

    throw err;
  }
});

/**
 * GET /auth/me
 *
 * Get current authenticated user information.
 * Requires Authorization header with Bearer token.
 * Note: This is a convenience endpoint not in the original spec.
 */
authRoutes.get('/auth/me', async (c) => {
  const service = getService();
  const requestId = getRequestId(c);

  try {
    // Extract token from Authorization header
    const authHeader = c.req.header('authorization');
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return c.json(
        error(
          ErrorCodes.UNAUTHORIZED,
          'Authorization header with Bearer token is required',
          requestId
        ),
        401 as const
      );
    }

    const token = authHeader.substring(7);

    // Verify token and get session data
    const session = await service.verifyAccessToken(token);

    // Get full user data
    const user = await service.getUserById(session.userId);

    if (!user) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, 'User not found', requestId),
        404 as const
      );
    }

    return c.json(
      success(user, {
        timing: { durationMs: getRequestDuration(c) },
      })
    );
  } catch (err) {
    if (err instanceof TokenExpiredError) {
      return c.json(
        error(ErrorCodes.UNAUTHORIZED, 'Access token has expired', requestId),
        401 as const
      );
    }

    if (err instanceof InvalidTokenError) {
      return c.json(
        error(ErrorCodes.UNAUTHORIZED, err.message, requestId),
        401 as const
      );
    }

    if (isMmsError(err)) {
      return c.json(
        error(err.code, err.message, requestId),
        err.statusCode as 400 | 401 | 403 | 404 | 409 | 422 | 500 | 502 | 503 | 504
      );
    }

    throw err;
  }
});

