/**
 * Man-hour Management Routes
 *
 * REST endpoints for man-hour projections and adjustment workflows.
 * Wraps ManHourLevelingService with HTTP interface per spec 005.7.
 *
 * Endpoints:
 * - GET /manhours/projections - List projections with filtering
 * - GET /manhours/adjustments - List proposed adjustments
 * - POST /manhours/adjustments/:id/approve - Approve an adjustment
 * - POST /manhours/adjustments/:id/reject - Reject an adjustment
 *
 * @see specs/005-api.md Section 5.7
 */

import { Hono } from 'hono';
import { parseISO } from 'date-fns';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getManHourLevelingService,
  type ProjectionFilters,
  type AdjustmentFilters,
  type AdjustmentStatus,
  type AdjustmentType,
} from '../../services';
import { isValidUuid } from '../../lib/schemas';

let manhourService: ReturnType<typeof getManHourLevelingService> | null = null;

function getService(): ReturnType<typeof getManHourLevelingService> {
  if (!manhourService) {
    manhourService = getManHourLevelingService();
  }
  return manhourService;
}

export const manhourRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * GET /manhours/projections
 *
 * Get man-hour projections with filtering.
 *
 * Query Parameters:
 * - depotId: Filter by depot
 * - fromDate: Period start (inclusive)
 * - toDate: Period end (inclusive)
 * - granularity: WEEKLY or MONTHLY
 * - projectionRunId: Filter by specific projection run
 */
manhourRoutes.get('/manhours/projections', async (c) => {
  const requestId = getRequestId(c);

  // Parse query filters
  const depotId = c.req.query('depotId');
  const fromDate = c.req.query('fromDate');
  const toDate = c.req.query('toDate');
  const projectionRunId = c.req.query('projectionRunId');

  // Validate UUIDs if provided
  if (depotId && !isValidUuid(depotId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'depotId must be a valid UUID', requestId), 400);
  }
  if (projectionRunId && !isValidUuid(projectionRunId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'projectionRunId must be a valid UUID', requestId), 400);
  }

  // Validate date formats
  if (fromDate && !/^\d{4}-\d{2}-\d{2}$/.test(fromDate)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'fromDate must be in YYYY-MM-DD format', requestId), 400);
  }
  if (toDate && !/^\d{4}-\d{2}-\d{2}$/.test(toDate)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'toDate must be in YYYY-MM-DD format', requestId), 400);
  }

  // Build filter object
  const filters: ProjectionFilters = {};
  if (depotId) filters.depotId = depotId;
  if (fromDate) filters.fromDate = parseISO(fromDate);
  if (toDate) filters.toDate = parseISO(toDate);
  if (projectionRunId) filters.projectionRunId = projectionRunId;

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
    sort: c.req.query('sort'),
  });

  const service = getService();
  const result = await service.getProjections(filters, pagination.page, pagination.pageSize);

  // Map to API response format per spec 005.7
  const data = result.data.map((projection) => {
    const requiredTotal = parseFloat(projection.requiredTotalHours ?? '0');
    const availableTotal = parseFloat(projection.availableTotalHours ?? '0');
    const varianceHours = availableTotal - requiredTotal;
    const utilizationPct = availableTotal > 0 ? (requiredTotal / availableTotal) * 100 : 0;

    return {
      depotId: projection.depotId,
      periodStart: projection.periodStart,
      periodEnd: projection.periodEnd,
      required: {
        pm: parseFloat(projection.requiredPmHours ?? '0'),
        corrective: parseFloat(projection.requiredCorrectiveHours ?? '0'),
        overhaul: parseFloat(projection.requiredOverhaulHours ?? '0'),
        total: requiredTotal,
      },
      available: {
        regular: parseFloat(projection.availableRegularHours ?? '0'),
        overtime: parseFloat(projection.availableOvertimeHours ?? '0'),
        total: availableTotal,
      },
      varianceHours,
      utilizationPct: Math.round(utilizationPct * 10) / 10,
      isOverloaded: requiredTotal > availableTotal,
      isUnderutilized: requiredTotal < availableTotal * 0.7,
      pendingAdjustments: 0, // TODO: Count adjustments when relation is loaded
    };
  });

  return c.json(
    paginatedSuccess(
      data,
      {
        page: result.page,
        pageSize: result.pageSize,
        totalItems: result.total,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * GET /manhours/adjustments
 *
 * Get proposed man-hour adjustments with filtering.
 *
 * Query Parameters:
 * - status: Filter by status (PROPOSED, APPROVED, REJECTED, APPLIED)
 * - type: Filter by adjustment type (ADVANCE_PM, DEFER_PM, ADD_OVERTIME, etc.)
 * - fromDate: Source period start (inclusive)
 * - toDate: Source period end (inclusive)
 */
manhourRoutes.get('/manhours/adjustments', async (c) => {
  const requestId = getRequestId(c);

  // Parse query filters
  const status = c.req.query('status');
  const type = c.req.query('type');
  const fromDate = c.req.query('fromDate');
  const toDate = c.req.query('toDate');

  // Validate status if provided
  const validStatuses: AdjustmentStatus[] = ['PROPOSED', 'APPROVED', 'REJECTED', 'APPLIED'];
  if (status && !validStatuses.includes(status as AdjustmentStatus)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `status must be one of: ${validStatuses.join(', ')}`,
        requestId
      ),
      400
    );
  }

  // Validate type if provided
  const validTypes: AdjustmentType[] = [
    'ADVANCE_PM',
    'DEFER_PM',
    'ADD_OVERTIME',
    'CROSS_DEPOT',
    'ADD_CONTRACTOR',
    'MANUAL_REVIEW',
  ];
  if (type && !validTypes.includes(type as AdjustmentType)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, `type must be one of: ${validTypes.join(', ')}`, requestId),
      400
    );
  }

  // Validate date formats
  if (fromDate && !/^\d{4}-\d{2}-\d{2}$/.test(fromDate)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'fromDate must be in YYYY-MM-DD format', requestId), 400);
  }
  if (toDate && !/^\d{4}-\d{2}-\d{2}$/.test(toDate)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'toDate must be in YYYY-MM-DD format', requestId), 400);
  }

  // Build filter object
  const filters: AdjustmentFilters = {};
  if (status) filters.status = status as AdjustmentStatus;
  if (type) filters.type = type as AdjustmentType;
  if (fromDate) filters.fromDate = parseISO(fromDate);
  if (toDate) filters.toDate = parseISO(toDate);

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
    sort: c.req.query('sort'),
  });

  const service = getService();
  const result = await service.getAdjustments(filters, pagination.page, pagination.pageSize);

  // Map to API response format per spec 005.7
  const data = result.data.map((adjustment) => ({
    id: adjustment.id,
    projectionId: adjustment.projectionId,
    type: adjustment.adjustmentType,
    sourcePeriod: {
      start: adjustment.sourcePeriodStart,
      end: adjustment.sourcePeriodEnd,
    },
    targetPeriod: adjustment.targetPeriodStart
      ? {
          start: adjustment.targetPeriodStart,
          end: adjustment.targetPeriodEnd,
        }
      : null,
    hoursAdjusted: parseFloat(adjustment.hoursAdjusted ?? '0'),
    affectedPMs: adjustment.affectedPmIds ?? [],
    costImpact: adjustment.costImpact ? parseFloat(adjustment.costImpact) : null,
    riskLevel: adjustment.riskImpact,
    reason: adjustment.reason,
    status: adjustment.status,
    proposedAt: adjustment.proposedAt,
  }));

  return c.json(
    paginatedSuccess(
      data,
      {
        page: result.page,
        pageSize: result.pageSize,
        totalItems: result.total,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * POST /manhours/adjustments/:id/approve
 *
 * Approve a man-hour adjustment.
 *
 * Request body:
 * - comment?: Optional approval comment
 */
manhourRoutes.post('/manhours/adjustments/:id/approve', async (c) => {
  const requestId = getRequestId(c);
  const adjustmentId = c.req.param('id');

  if (!isValidUuid(adjustmentId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid adjustment ID format', requestId), 400);
  }

  const body = await c.req.json().catch(() => ({}));
  const user = c.get('user');
  const userId = user?.id ?? 'system';

  const service = getService();
  const updated = await service.approveAdjustment(adjustmentId, userId);

  return c.json(
    success({
      id: updated.id,
      status: updated.status,
      approvedBy: updated.approvedBy,
      approvedAt: updated.approvedAt,
      comment: body.comment ?? null,
    })
  );
});

/**
 * POST /manhours/adjustments/:id/reject
 *
 * Reject a man-hour adjustment.
 *
 * Request body:
 * - reason: Reason for rejection (required)
 */
manhourRoutes.post('/manhours/adjustments/:id/reject', async (c) => {
  const requestId = getRequestId(c);
  const adjustmentId = c.req.param('id');

  if (!isValidUuid(adjustmentId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid adjustment ID format', requestId), 400);
  }

  const body = await c.req.json();

  // Validate reason is provided
  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'reason is required for rejection', requestId),
      400
    );
  }

  const user = c.get('user');
  const userId = user?.id ?? 'system';

  const service = getService();
  const updated = await service.rejectAdjustment(adjustmentId, userId, body.reason);

  return c.json(
    success({
      id: updated.id,
      status: updated.status,
      rejectedBy: updated.approvedBy, // Same field used for rejections
      rejectedAt: updated.approvedAt,
      rejectionReason: updated.rejectionReason,
    })
  );
});

