/**
 * Drift Analysis Routes
 *
 * REST endpoints for drift analysis monitoring.
 * Drift analysis compares actual fleet state against published baselines
 * to detect schedule and mileage deviations requiring attention.
 *
 * @see specs/005-api.md Section 5.9
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getDriftMonitorService,
  getBaselineService,
  type DriftHistoryFilters,
} from '../../services';
import { isValidUuid } from '../../lib/schemas';

// Singleton service instances
let driftService: ReturnType<typeof getDriftMonitorService> | null = null;
let baselineService: ReturnType<typeof getBaselineService> | null = null;

function getDriftService(): ReturnType<typeof getDriftMonitorService> {
  if (!driftService) {
    driftService = getDriftMonitorService();
  }
  return driftService;
}

function getBaseline(): ReturnType<typeof getBaselineService> {
  if (!baselineService) {
    baselineService = getBaselineService();
  }
  return baselineService;
}

export const driftRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * Map drift severity based on whether replan is required
 */
function getDriftSeverity(
  mileageDriftPct: number,
  maxPmDriftDays: number,
  requiresReplan: boolean,
  thresholds: { mileageDriftPct: number; scheduleDriftDays: number }
): 'GREEN' | 'YELLOW' | 'RED' {
  if (requiresReplan) {
    return 'RED';
  }

  // Approaching threshold (>70% of threshold)
  const mileageApproaching = Math.abs(mileageDriftPct) > thresholds.mileageDriftPct * 0.7;
  const scheduleApproaching = maxPmDriftDays > thresholds.scheduleDriftDays * 0.7;

  if (mileageApproaching || scheduleApproaching) {
    return 'YELLOW';
  }

  return 'GREEN';
}

/**
 * GET /drift/analysis
 *
 * Get drift analysis results comparing actual state against baseline.
 * Returns the latest drift analysis with summary and per-train details.
 *
 * Query Parameters:
 * - baselineId: Filter by specific baseline (UUID, optional - defaults to latest published)
 * - trainId: Filter by specific train (UUID, optional)
 * - requiresReplan: Filter trains requiring replan (boolean, optional)
 * - page: Page number for train analyses (default: 1)
 * - pageSize: Items per page (default: 50, max: 200)
 */
driftRoutes.get('/drift/analysis', async (c) => {
  const requestId = getRequestId(c);
  const service = getDriftService();
  const baselines = getBaseline();

  // Parse query parameters
  const baselineIdParam = c.req.query('baselineId');
  const trainIdParam = c.req.query('trainId');
  const requiresReplanParam = c.req.query('requiresReplan');

  // Validate UUIDs if provided
  if (baselineIdParam && !isValidUuid(baselineIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId),
      400
    );
  }

  if (trainIdParam && !isValidUuid(trainIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid train ID format', requestId),
      400
    );
  }

  // Get baseline (specific or latest published)
  let baseline;
  if (baselineIdParam) {
    try {
      baseline = await baselines.getBaselineById(baselineIdParam);
    } catch {
      return c.json(
        error(ErrorCodes.NOT_FOUND, `Baseline not found: ${baselineIdParam}`, requestId),
        404
      );
    }
  } else {
    baseline = await baselines.getLatestBaseline();
    if (!baseline) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, 'No published baseline found', requestId),
        404
      );
    }
  }

  // Build filters for drift history query
  const filters: DriftHistoryFilters = {
    baselineId: baseline.id,
  };

  if (trainIdParam) {
    filters.trainId = trainIdParam;
  }

  if (requiresReplanParam !== undefined) {
    filters.requiresReplan = requiresReplanParam === 'true';
  }

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
  });

  // Get drift summary
  const summary = await service.getDriftSummary(baseline.id);

  // Get drift history (train analyses)
  const driftHistory = await service.getDriftHistory(filters, {
    page: pagination.page,
    pageSize: pagination.pageSize,
  });

  // Get current thresholds for severity calculation
  const thresholds = service.getThresholds();

  // Map to API response format per spec 005.9
  const trainAnalyses = driftHistory.data.map((drift) => ({
    trainId: drift.trainId,
    trainNumber: null, // Would need train lookup for number
    baselineProjectedKm: drift.baselineProjectedKm,
    actualKm: drift.actualKm,
    mileageDriftKm: drift.actualKm - drift.baselineProjectedKm,
    mileageDriftPct: drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
    pmDrifts: [], // PM drift details would need to be stored/retrieved separately
    avgPmDriftDays: drift.avgPmDriftDays ? parseFloat(drift.avgPmDriftDays) : 0,
    maxPmDriftDays: drift.maxPmDriftDays ?? 0,
    requiresReplan: drift.requiresReplan,
    replanReason: drift.replanReason,
    driftSeverity: getDriftSeverity(
      drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
      drift.maxPmDriftDays ?? 0,
      drift.requiresReplan ?? false,
      thresholds
    ),
  }));

  // Build response
  const responseData = {
    baselineId: baseline.id,
    baselineName: baseline.name,
    baselineVersion: baseline.version,
    analysisDate: driftHistory.data[0]?.analysisDate ?? null,
    summary: summary
      ? {
          totalTrains: summary.totalTrains,
          trainsWithDrift: summary.trainsWithDrift,
          trainsRequiringReplan: summary.trainsRequiringReplan,
          avgFleetDriftPct: Math.round(summary.avgMileageDriftPct * 100) / 100,
          maxMileageDriftPct: Math.round(summary.maxMileageDriftPct * 100) / 100,
          avgPmDriftDays: Math.round(summary.avgPmDriftDays * 10) / 10,
          maxPmDriftDays: summary.maxPmDriftDays,
        }
      : {
          totalTrains: 0,
          trainsWithDrift: 0,
          trainsRequiringReplan: 0,
          avgFleetDriftPct: 0,
          maxMileageDriftPct: 0,
          avgPmDriftDays: 0,
          maxPmDriftDays: 0,
        },
    trainAnalyses,
  };

  // Return paginated response if filtering by train or paginating through results
  if (driftHistory.total > driftHistory.pageSize) {
    return c.json(
      paginatedSuccess(
        [responseData],
        {
          page: driftHistory.page,
          pageSize: driftHistory.pageSize,
          totalItems: driftHistory.total,
        },
        { durationMs: getRequestDuration(c) }
      )
    );
  }

  return c.json(
    success(responseData, {
      timing: { durationMs: getRequestDuration(c) },
    })
  );
});

/**
 * GET /drift/trains-requiring-replan
 *
 * Convenience endpoint to get only trains that require replanning.
 * Returns a focused list for immediate action.
 */
driftRoutes.get('/drift/trains-requiring-replan', async (c) => {
  const requestId = getRequestId(c);
  const service = getDriftService();
  const baselines = getBaseline();

  // Get latest baseline
  const baseline = await baselines.getLatestBaseline();
  if (!baseline) {
    return c.json(
      error(ErrorCodes.NOT_FOUND, 'No published baseline found', requestId),
      404
    );
  }

  // Get trains requiring replan
  const trains = await service.getTrainsRequiringReplan();

  // Get thresholds for severity calculation
  const thresholds = service.getThresholds();

  // Map to response format
  const data = trains.map((drift) => ({
    trainId: drift.trainId,
    analysisDate: drift.analysisDate,
    baselineProjectedKm: drift.baselineProjectedKm,
    actualKm: drift.actualKm,
    mileageDriftKm: drift.actualKm - drift.baselineProjectedKm,
    mileageDriftPct: drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
    avgPmDriftDays: drift.avgPmDriftDays ? parseFloat(drift.avgPmDriftDays) : 0,
    maxPmDriftDays: drift.maxPmDriftDays ?? 0,
    replanReason: drift.replanReason,
    driftSeverity: getDriftSeverity(
      drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
      drift.maxPmDriftDays ?? 0,
      true,
      thresholds
    ),
  }));

  return c.json(
    success(
      {
        baselineId: baseline.id,
        baselineName: baseline.name,
        count: data.length,
        trains: data,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /drift/summary
 *
 * Get drift analysis summary for the latest baseline.
 * Convenience endpoint for dashboard display.
 */
driftRoutes.get('/drift/summary', async (c) => {
  const requestId = getRequestId(c);
  const service = getDriftService();
  const baselines = getBaseline();

  const baselineIdParam = c.req.query('baselineId');
  const analysisDateParam = c.req.query('analysisDate');

  // Validate UUID if provided
  if (baselineIdParam && !isValidUuid(baselineIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId),
      400
    );
  }

  // Get baseline
  let baseline;
  if (baselineIdParam) {
    try {
      baseline = await baselines.getBaselineById(baselineIdParam);
    } catch {
      return c.json(
        error(ErrorCodes.NOT_FOUND, `Baseline not found: ${baselineIdParam}`, requestId),
        404
      );
    }
  } else {
    baseline = await baselines.getLatestBaseline();
    if (!baseline) {
      return c.json(
        error(ErrorCodes.NOT_FOUND, 'No published baseline found', requestId),
        404
      );
    }
  }

  // Get summary
  const summary = await service.getDriftSummary(baseline.id, analysisDateParam);

  if (!summary) {
    return c.json(
      success(
        {
          baselineId: baseline.id,
          baselineName: baseline.name,
          analysisDate: null,
          hasAnalysis: false,
          summary: null,
        },
        { timing: { durationMs: getRequestDuration(c) } }
      )
    );
  }

  // Get thresholds for context
  const thresholds = service.getThresholds();

  return c.json(
    success(
      {
        baselineId: baseline.id,
        baselineName: baseline.name,
        hasAnalysis: true,
        summary: {
          totalTrains: summary.totalTrains,
          trainsWithDrift: summary.trainsWithDrift,
          trainsRequiringReplan: summary.trainsRequiringReplan,
          avgMileageDriftPct: Math.round(summary.avgMileageDriftPct * 100) / 100,
          maxMileageDriftPct: Math.round(summary.maxMileageDriftPct * 100) / 100,
          avgPmDriftDays: Math.round(summary.avgPmDriftDays * 10) / 10,
          maxPmDriftDays: summary.maxPmDriftDays,
        },
        thresholds: {
          mileageDriftPct: thresholds.mileageDriftPct,
          scheduleDriftDays: thresholds.scheduleDriftDays,
          fleetDriftTrainCount: thresholds.fleetDriftTrainCount,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /drift/history
 *
 * Get historical drift analysis records with filtering and pagination.
 * Useful for trending and audit purposes.
 *
 * Query Parameters:
 * - baselineId: Filter by baseline (UUID)
 * - trainId: Filter by train (UUID)
 * - fromDate: Filter by analysis date (ISO date)
 * - toDate: Filter by analysis date (ISO date)
 * - requiresReplan: Filter by replan status (boolean)
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 50, max: 200)
 */
driftRoutes.get('/drift/history', async (c) => {
  const requestId = getRequestId(c);
  const service = getDriftService();

  // Parse query parameters
  const baselineIdParam = c.req.query('baselineId');
  const trainIdParam = c.req.query('trainId');
  const fromDateParam = c.req.query('fromDate');
  const toDateParam = c.req.query('toDate');
  const requiresReplanParam = c.req.query('requiresReplan');

  // Validate UUIDs
  if (baselineIdParam && !isValidUuid(baselineIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid baseline ID format', requestId),
      400
    );
  }

  if (trainIdParam && !isValidUuid(trainIdParam)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid train ID format', requestId),
      400
    );
  }

  // Build filters
  const filters: DriftHistoryFilters = {};

  if (baselineIdParam) {
    filters.baselineId = baselineIdParam;
  }

  if (trainIdParam) {
    filters.trainId = trainIdParam;
  }

  if (fromDateParam) {
    const parsed = new Date(fromDateParam);
    if (!isNaN(parsed.getTime())) {
      filters.fromDate = parsed;
    }
  }

  if (toDateParam) {
    const parsed = new Date(toDateParam);
    if (!isNaN(parsed.getTime())) {
      filters.toDate = parsed;
    }
  }

  if (requiresReplanParam !== undefined) {
    filters.requiresReplan = requiresReplanParam === 'true';
  }

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
  });

  // Get drift history
  const result = await service.getDriftHistory(filters, {
    page: pagination.page,
    pageSize: pagination.pageSize,
  });

  // Map to API response format
  const data = result.data.map((drift) => ({
    id: drift.id,
    baselineId: drift.baselineId,
    trainId: drift.trainId,
    analysisDate: drift.analysisDate,
    baselineProjectedKm: drift.baselineProjectedKm,
    actualKm: drift.actualKm,
    mileageDriftPct: drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
    avgPmDriftDays: drift.avgPmDriftDays ? parseFloat(drift.avgPmDriftDays) : 0,
    maxPmDriftDays: drift.maxPmDriftDays ?? 0,
    requiresReplan: drift.requiresReplan,
    replanReason: drift.replanReason,
    createdAt: drift.createdAt,
  }));

  return c.json(
    paginatedSuccess(
      data,
      {
        page: result.page,
        pageSize: result.pageSize,
        totalItems: result.total,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * POST /drift/run-analysis
 *
 * Trigger a drift analysis run.
 * Typically run as a nightly job, but can be triggered manually.
 * Requires appropriate permissions (admin or scheduler role).
 *
 * Request Body:
 * - analysisDate: Optional date for analysis (ISO date, defaults to today)
 */
driftRoutes.post('/drift/run-analysis', async (c) => {
  const requestId = getRequestId(c);
  const service = getDriftService();

  // Parse request body
  let analysisDate: Date | undefined;
  try {
    const body = await c.req.json();
    if (body.analysisDate) {
      analysisDate = new Date(body.analysisDate);
      if (isNaN(analysisDate.getTime())) {
        return c.json(
          error(ErrorCodes.VALIDATION_ERROR, 'Invalid analysis date format', requestId),
          400
        );
      }
    }
  } catch {
    // Empty body is fine, use default date
  }

  // Run analysis
  const result = await service.runDriftAnalysis(analysisDate);

  if (result.skipped) {
    return c.json(
      success(
        {
          status: 'skipped',
          reason: result.reason,
        },
        { timing: { durationMs: getRequestDuration(c) } }
      )
    );
  }

  return c.json(
    success(
      {
        status: 'completed',
        baselineId: result.baselineId,
        baselineVersion: result.baselineVersion,
        analysisDate: result.analysisDate,
        summary: result.summary,
        alertCount: result.alerts.length,
        alerts: result.alerts,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * GET /drift/train/:trainId
 *
 * Get the latest drift analysis for a specific train.
 * Convenience endpoint for train detail views.
 */
driftRoutes.get('/drift/train/:trainId', async (c) => {
  const requestId = getRequestId(c);
  const trainId = c.req.param('trainId');

  if (!isValidUuid(trainId)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid train ID format', requestId),
      400
    );
  }

  const service = getDriftService();

  try {
    const drift = await service.getLatestTrainDrift(trainId);
    const thresholds = service.getThresholds();

    return c.json(
      success(
        {
          trainId: drift.trainId,
          baselineId: drift.baselineId,
          analysisDate: drift.analysisDate,
          baselineProjectedKm: drift.baselineProjectedKm,
          actualKm: drift.actualKm,
          mileageDriftKm: drift.actualKm - drift.baselineProjectedKm,
          mileageDriftPct: drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
          avgPmDriftDays: drift.avgPmDriftDays ? parseFloat(drift.avgPmDriftDays) : 0,
          maxPmDriftDays: drift.maxPmDriftDays ?? 0,
          requiresReplan: drift.requiresReplan,
          replanReason: drift.replanReason,
          driftSeverity: getDriftSeverity(
            drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
            drift.maxPmDriftDays ?? 0,
            drift.requiresReplan ?? false,
            thresholds
          ),
        },
        { timing: { durationMs: getRequestDuration(c) } }
      )
    );
  } catch {
    return c.json(
      error(ErrorCodes.NOT_FOUND, `No drift analysis found for train: ${trainId}`, requestId),
      404
    );
  }
});

