/**
 * Scenario Management Routes
 *
 * REST endpoints for what-if scenario analysis.
 * Scenarios enable users to explore alternative planning outcomes
 * without affecting the production schedule.
 *
 * Key features:
 * - Fork from baselines or other scenarios
 * - Apply changes (PM moves, adds, removes)
 * - Compare scenarios side-by-side
 * - Promote winning scenarios to new baselines
 *
 * @see specs/005-api.md Section 5.10
 */

import { Hono } from 'hono';
import {
  success,
  paginatedSuccess,
  error,
  parsePaginationQuery,
  ErrorCodes,
  type AppVariables,
} from '../types';
import { getRequestId, getRequestDuration } from '../middleware/request-context';
import {
  getSimulationService,
  type ScenarioListFilters,
  type ScenarioStatus,
  type DeltaType,
  type EntityType,
} from '../../services';
import { isValidUuid } from '../../lib/schemas';

// Singleton service instance
let simulationService: ReturnType<typeof getSimulationService> | null = null;

function getService(): ReturnType<typeof getSimulationService> {
  if (!simulationService) {
    simulationService = getSimulationService();
  }
  return simulationService;
}

export const scenarioRoutes = new Hono<{ Variables: AppVariables }>();

/**
 * GET /scenarios
 *
 * List scenarios with filtering and pagination.
 *
 * Query Parameters:
 * - status: Filter by status (ACTIVE, PROMOTED, DISCARDED, EXPIRED)
 * - createdBy: Filter by creator user ID
 * - forkedFromBaselineId: Filter by source baseline
 * - forkedFromScenarioId: Filter by source scenario
 * - includeExpired: Include expired scenarios (default: false)
 * - page: Page number (default: 1)
 * - pageSize: Items per page (default: 20, max: 100)
 * - sort: Sort field (name:asc, createdAt:desc, lastModifiedAt:desc, expiresAt:asc)
 */
scenarioRoutes.get('/scenarios', async (c) => {
  const service = getService();

  // Parse query filters
  const filters: ScenarioListFilters = {};
  const status = c.req.query('status');
  const createdBy = c.req.query('createdBy');
  const forkedFromBaselineId = c.req.query('forkedFromBaselineId');
  const forkedFromScenarioId = c.req.query('forkedFromScenarioId');
  const includeExpired = c.req.query('includeExpired') === 'true';

  if (status) {
    const validStatuses: ScenarioStatus[] = ['ACTIVE', 'PROMOTED', 'DISCARDED', 'EXPIRED'];
    const statusValues = status.split(',').filter((s) => validStatuses.includes(s as ScenarioStatus));
    if (statusValues.length === 1) {
      filters.status = statusValues[0] as ScenarioStatus;
    } else if (statusValues.length > 1) {
      filters.status = statusValues as ScenarioStatus[];
    }
  }

  if (createdBy) {
    filters.createdBy = createdBy;
  }

  if (forkedFromBaselineId && isValidUuid(forkedFromBaselineId)) {
    filters.forkedFromBaselineId = forkedFromBaselineId;
  }

  if (forkedFromScenarioId && isValidUuid(forkedFromScenarioId)) {
    filters.forkedFromScenarioId = forkedFromScenarioId;
  }

  filters.includeExpired = includeExpired;

  // Parse pagination
  const pagination = parsePaginationQuery({
    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
    sort: c.req.query('sort'),
  });

  const result = await service.listScenarios(filters, {
    page: pagination.page,
    pageSize: Math.min(pagination.pageSize, 100),
    sortBy: pagination.sort?.field as 'name' | 'createdAt' | 'lastModifiedAt' | 'expiresAt' | undefined,
    sortOrder: pagination.sort?.direction,
  });

  // Map to API response format per spec 005.10
  const scenarios = result.data.map((scenario) => ({
    id: scenario.id,
    name: scenario.name,
    description: scenario.description,
    status: scenario.status,
    forkedFromBaselineId: scenario.forkedFromBaselineId,
    forkedFromBaselineName: scenario.forkedFromBaselineName,
    forkedFromScenarioId: scenario.forkedFromScenarioId,
    forkedFromScenarioName: scenario.forkedFromScenarioName,
    forkedAt: scenario.forkedAt,
    createdBy: scenario.createdBy
      ? { id: scenario.createdBy, displayName: scenario.createdByEmail ?? null }
      : null,
    createdAt: scenario.createdAt,
    lastModifiedAt: scenario.lastModifiedAt,
    expiresAt: scenario.expiresAt,
    deltaCount: scenario.deltaCount ?? 0,
  }));

  return c.json(
    paginatedSuccess(
      scenarios,
      {
        page: result.page,
        pageSize: result.pageSize,
        totalItems: result.total,
      },
      { durationMs: getRequestDuration(c) }
    )
  );
});

/**
 * GET /scenarios/:id
 *
 * Get scenario details by ID.
 */
scenarioRoutes.get('/scenarios/:id', async (c) => {
  const requestId = getRequestId(c);
  const scenarioId = c.req.param('id');

  if (!isValidUuid(scenarioId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
  }

  const service = getService();
  const scenario = await service.getScenario(scenarioId);

  return c.json(
    success(
      {
        id: scenario.id,
        name: scenario.name,
        description: scenario.description,
        status: scenario.status,
        forkedFromBaselineId: scenario.forkedFromBaselineId,
        forkedFromBaselineName: scenario.forkedFromBaselineName,
        forkedFromScenarioId: scenario.forkedFromScenarioId,
        forkedFromScenarioName: scenario.forkedFromScenarioName,
        forkedAt: scenario.forkedAt,
        createdBy: scenario.createdBy
          ? { id: scenario.createdBy, displayName: scenario.createdByEmail ?? null }
          : null,
        createdAt: scenario.createdAt,
        lastModifiedAt: scenario.lastModifiedAt,
        expiresAt: scenario.expiresAt,
        deltaCount: scenario.deltaCount ?? 0,
        promotedToBaselineId: scenario.promotedToBaselineId,
        promotedAt: scenario.promotedAt,
        promotedBy: scenario.promotedBy,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * POST /scenarios
 *
 * Create a new scenario forked from a baseline, another scenario, or production.
 *
 * Request body:
 * - name: Scenario name (required)
 * - description: Optional description
 * - forkFrom: Fork source specification (required)
 *   - type: 'BASELINE' | 'SCENARIO' | 'PRODUCTION'
 *   - id: Source ID (required for BASELINE and SCENARIO)
 * - expirationDays: Days until expiration (default: 30)
 */
scenarioRoutes.post('/scenarios', async (c) => {
  const requestId = getRequestId(c);
  const body = await c.req.json();

  // Validate required fields
  if (!body.name || typeof body.name !== 'string' || body.name.trim().length === 0) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Scenario name is required', requestId),
      400
    );
  }

  if (!body.forkFrom || typeof body.forkFrom !== 'object') {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'forkFrom specification is required', requestId),
      400
    );
  }

  const validForkTypes = ['BASELINE', 'SCENARIO', 'PRODUCTION'];
  if (!validForkTypes.includes(body.forkFrom.type)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `forkFrom.type must be one of: ${validForkTypes.join(', ')}`,
        requestId
      ),
      400
    );
  }

  // Validate ID is provided for BASELINE and SCENARIO types
  if ((body.forkFrom.type === 'BASELINE' || body.forkFrom.type === 'SCENARIO') && !body.forkFrom.id) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `forkFrom.id is required for type ${body.forkFrom.type}`,
        requestId
      ),
      400
    );
  }

  if (body.forkFrom.id && !isValidUuid(body.forkFrom.id)) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'Invalid forkFrom.id format', requestId),
      400
    );
  }

  // Get user from context
  const userId = c.get('user')?.id ?? 'system';

  const service = getService();
  const scenario = await service.createScenario({
    name: body.name.trim(),
    description: body.description?.trim(),
    forkFrom: body.forkFrom,
    userId,
    expirationDays: body.expirationDays ? Number(body.expirationDays) : undefined,
  });

  return c.json(
    success(
      {
        id: scenario.id,
        name: scenario.name,
        description: scenario.description,
        status: scenario.status,
        forkedFromBaselineId: scenario.forkedFromBaselineId,
        forkedFromScenarioId: scenario.forkedFromScenarioId,
        forkedAt: scenario.forkedAt,
        createdAt: scenario.createdAt,
        expiresAt: scenario.expiresAt,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    ),
    201
  );
});

/**
 * DELETE /scenarios/:id
 *
 * Delete a scenario. Only ACTIVE scenarios can be deleted.
 * PROMOTED scenarios cannot be deleted as they are part of the audit trail.
 */
scenarioRoutes.delete('/scenarios/:id', async (c) => {
  const requestId = getRequestId(c);
  const scenarioId = c.req.param('id');

  if (!isValidUuid(scenarioId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
  }

  const userId = c.get('user')?.id ?? 'system';

  const service = getService();
  await service.deleteScenario(scenarioId, userId);

  return c.json(
    success({ deleted: true, scenarioId }, { timing: { durationMs: getRequestDuration(c) } })
  );
});

/**
 * POST /scenarios/:id/changes
 *
 * Apply a change (delta) to a scenario.
 *
 * Request body:
 * - type: Delta type ('PM_MOVE' | 'PM_ADD' | 'PM_REMOVE' | 'CAPACITY_CHANGE' | 'TRAIN_STATUS_CHANGE')
 * - entityType: Entity being modified ('pm_schedule' | 'manhour_capacity' | 'train')
 * - entityId: ID of the entity being modified
 * - oldValues: Previous values (optional, for audit)
 * - newValues: New values (required for PM_MOVE and PM_ADD)
 * - reason: Change reason (optional)
 */
scenarioRoutes.post('/scenarios/:id/changes', async (c) => {
  const requestId = getRequestId(c);
  const scenarioId = c.req.param('id');

  if (!isValidUuid(scenarioId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
  }

  const body = await c.req.json();

  // Validate required fields
  const validDeltaTypes: DeltaType[] = ['PM_MOVE', 'PM_ADD', 'PM_REMOVE', 'CAPACITY_CHANGE', 'TRAIN_STATUS_CHANGE'];
  if (!body.type || !validDeltaTypes.includes(body.type)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `type must be one of: ${validDeltaTypes.join(', ')}`,
        requestId
      ),
      400
    );
  }

  const validEntityTypes: EntityType[] = ['pm_schedule', 'manhour_capacity', 'train'];
  if (!body.entityType || !validEntityTypes.includes(body.entityType)) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `entityType must be one of: ${validEntityTypes.join(', ')}`,
        requestId
      ),
      400
    );
  }

  if (!body.entityId || typeof body.entityId !== 'string') {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'entityId is required', requestId),
      400
    );
  }

  // Validate newValues for specific delta types
  if ((body.type === 'PM_MOVE' || body.type === 'PM_ADD') && !body.newValues) {
    return c.json(
      error(
        ErrorCodes.VALIDATION_ERROR,
        `newValues is required for ${body.type}`,
        requestId
      ),
      400
    );
  }

  if (body.type === 'PM_ADD') {
    const newValues = body.newValues;
    if (!newValues.trainId || !newValues.pmTypeId || !newValues.targetDate) {
      return c.json(
        error(
          ErrorCodes.VALIDATION_ERROR,
          'PM_ADD requires trainId, pmTypeId, and targetDate in newValues',
          requestId
        ),
        400
      );
    }
  }

  const userId = c.get('user')?.id ?? 'system';

  const service = getService();
  const delta = await service.applyChange(
    scenarioId,
    {
      type: body.type,
      entityType: body.entityType,
      entityId: body.entityId,
      oldValues: body.oldValues,
      newValues: body.newValues,
      reason: body.reason,
    },
    userId
  );

  return c.json(
    success(
      {
        id: delta.id,
        scenarioId: delta.scenarioId,
        sequenceNum: delta.sequenceNum,
        deltaType: delta.deltaType,
        entityType: delta.entityType,
        entityId: delta.entityId,
        createdAt: delta.createdAt,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    ),
    201
  );
});

/**
 * GET /scenarios/:id/changes
 *
 * Get all changes (deltas) applied to a scenario in order.
 */
scenarioRoutes.get('/scenarios/:id/changes', async (c) => {
  const requestId = getRequestId(c);
  const scenarioId = c.req.param('id');

  if (!isValidUuid(scenarioId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
  }

  const service = getService();
  const deltas = await service.getScenarioDeltas(scenarioId);

  const changes = deltas.map((delta) => ({
    id: delta.id,
    sequenceNum: delta.sequenceNum,
    deltaType: delta.deltaType,
    entityType: delta.entityType,
    entityId: delta.entityId,
    oldValues: delta.oldValues,
    newValues: delta.newValues,
    changeReason: delta.changeReason,
    createdBy: delta.createdBy,
    createdAt: delta.createdAt,
  }));

  return c.json(
    success(changes, { timing: { durationMs: getRequestDuration(c) } })
  );
});

/**
 * POST /scenarios/:id/undo
 *
 * Undo the last change applied to a scenario.
 */
scenarioRoutes.post('/scenarios/:id/undo', async (c) => {
  const requestId = getRequestId(c);
  const scenarioId = c.req.param('id');

  if (!isValidUuid(scenarioId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
  }

  const userId = c.get('user')?.id ?? 'system';

  const service = getService();
  await service.undoLastChange(scenarioId, userId);

  return c.json(
    success({ undone: true, scenarioId }, { timing: { durationMs: getRequestDuration(c) } })
  );
});

/**
 * GET /scenarios/:id/materialized
 *
 * Get the materialized (fully computed) state of a scenario.
 * This applies all deltas to the base state and returns the resulting PM schedule.
 */
scenarioRoutes.get('/scenarios/:id/materialized', async (c) => {
  const requestId = getRequestId(c);
  const scenarioId = c.req.param('id');

  if (!isValidUuid(scenarioId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
  }

  const service = getService();
  const materialized = await service.materializeScenario(scenarioId);

  return c.json(
    success(
      {
        scenario: materialized.scenario
          ? {
              id: materialized.scenario.id,
              name: materialized.scenario.name,
              status: materialized.scenario.status,
            }
          : null,
        baselineId: materialized.baselineId,
        baselineVersion: materialized.baselineVersion,
        deltasApplied: materialized.deltasApplied,
        pmSchedule: materialized.pmSchedule.map((pm) => ({
          id: pm.id,
          trainId: pm.trainId,
          trainNumber: pm.trainNumber,
          pmTypeId: pm.pmTypeId,
          pmCode: pm.pmCode,
          targetDate: pm.targetDate,
          assignedTrackId: pm.assignedTrackId,
          assignedHours: pm.assignedHours,
          status: pm.status,
          constraintStart: pm.constraintStart,
          constraintEnd: pm.constraintEnd,
          isLocked: pm.isLocked,
        })),
        pmCount: materialized.pmSchedule.length,
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * POST /scenarios/:id/compare
 *
 * Compare a scenario to a baseline or another scenario.
 *
 * Request body:
 * - compareTo: Comparison target specification
 *   - type: 'BASELINE' | 'SCENARIO'
 *   - id: Target ID (optional for BASELINE - uses latest published)
 */
scenarioRoutes.post('/scenarios/:id/compare', async (c) => {
  const requestId = getRequestId(c);
  const scenarioId = c.req.param('id');

  if (!isValidUuid(scenarioId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
  }

  const body = await c.req.json();

  // Default to comparing with latest baseline if not specified
  let scenarioBId: string | null = null;
  let baselineId: string | undefined;

  if (body.compareTo) {
    if (body.compareTo.type === 'SCENARIO') {
      if (!body.compareTo.id) {
        return c.json(
          error(ErrorCodes.VALIDATION_ERROR, 'compareTo.id is required for SCENARIO type', requestId),
          400
        );
      }
      if (!isValidUuid(body.compareTo.id)) {
        return c.json(
          error(ErrorCodes.VALIDATION_ERROR, 'Invalid compareTo.id format', requestId),
          400
        );
      }
      scenarioBId = body.compareTo.id;
    } else if (body.compareTo.type === 'BASELINE' && body.compareTo.id) {
      if (!isValidUuid(body.compareTo.id)) {
        return c.json(
          error(ErrorCodes.VALIDATION_ERROR, 'Invalid compareTo.id format', requestId),
          400
        );
      }
      baselineId = body.compareTo.id;
    }
  }

  const service = getService();
  const comparison = await service.compareScenarios(scenarioId, scenarioBId, baselineId);

  return c.json(
    success(
      {
        comparison: {
          comparisonId: comparison.comparisonId,
          scenarioA: comparison.scenarioAId,
          scenarioAName: comparison.scenarioAName,
          scenarioB: comparison.scenarioBId ?? null,
          scenarioBName: comparison.scenarioBName,
          baselineId: comparison.baselineId,
          baselineVersion: comparison.baselineVersion,
          comparisonDate: comparison.comparisonDate,
        },
        summary: {
          pmCountDelta: comparison.pmDifferences.countDelta,
          pmAdded: comparison.pmDifferences.added,
          pmRemoved: comparison.pmDifferences.removed,
          pmMoved: comparison.pmDifferences.moved,
          pmUnchanged: comparison.pmDifferences.unchanged,
          totalHoursDelta: comparison.manhourDifferences.totalDelta,
          totalCostDelta: comparison.costDifferences.totalDelta,
          overloadedWeeksDelta: comparison.manhourDifferences.overloadedWeeksDelta,
        },
        pmDifferences: comparison.pmDifferences.details.map((diff) => ({
          pmId: diff.pmId,
          trainId: diff.trainId,
          trainNumber: diff.trainNumber,
          pmTypeId: diff.pmTypeId,
          pmCode: diff.pmCode,
          changeType: diff.changeType,
          scenarioADate: diff.scenarioADate,
          scenarioBDate: diff.scenarioBDate,
          daysDifference: diff.daysDifference,
        })),
        manhourImpact: {
          scenarioATotalHours: comparison.manhourDifferences.scenarioATotalHours,
          scenarioBTotalHours: comparison.manhourDifferences.scenarioBTotalHours,
          weeklyChanges: comparison.manhourDifferences.details,
        },
        costImpact: {
          scenarioATotalCost: comparison.costDifferences.scenarioATotalCost,
          scenarioBTotalCost: comparison.costDifferences.scenarioBTotalCost,
          laborDelta: comparison.costDifferences.laborDelta,
          materialDelta: comparison.costDifferences.materialDelta,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

/**
 * POST /scenarios/:id/promote
 *
 * Promote a scenario to become the new production baseline.
 * This will:
 * 1. Materialize all scenario deltas
 * 2. Create a new published baseline
 * 3. Apply the deltas to the production PM schedule
 * 4. Mark the scenario as PROMOTED
 * 5. Supersede any previous published baseline
 *
 * Request body:
 * - baselineName: Name for the new baseline (required)
 * - description: Optional description
 */
scenarioRoutes.post('/scenarios/:id/promote', async (c) => {
  const requestId = getRequestId(c);
  const scenarioId = c.req.param('id');

  if (!isValidUuid(scenarioId)) {
    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
  }

  const body = await c.req.json();

  // Validate required fields
  if (!body.baselineName || typeof body.baselineName !== 'string' || body.baselineName.trim().length === 0) {
    return c.json(
      error(ErrorCodes.VALIDATION_ERROR, 'baselineName is required', requestId),
      400
    );
  }

  const userId = c.get('user')?.id ?? 'system';

  const service = getService();
  const baseline = await service.promoteToBaseline({
    scenarioId,
    baselineName: body.baselineName.trim(),
    baselineDescription: body.description?.trim(),
    userId,
  });

  return c.json(
    success(
      {
        promoted: true,
        scenarioId,
        baseline: {
          id: baseline.id,
          name: baseline.name,
          version: baseline.version,
          baselineDate: baseline.baselineDate,
          status: baseline.status,
          publishedAt: baseline.publishedAt,
        },
      },
      { timing: { durationMs: getRequestDuration(c) } }
    ),
    201
  );
});

/**
 * POST /scenarios/cleanup
 *
 * Manually trigger cleanup of expired scenarios.
 * Normally this runs as a scheduled job.
 */
scenarioRoutes.post('/scenarios/cleanup', async (c) => {
  const service = getService();
  const expiredCount = await service.cleanupExpiredScenarios();

  return c.json(
    success(
      { cleaned: true, expiredCount },
      { timing: { durationMs: getRequestDuration(c) } }
    )
  );
});

