     1→/**
     2→ * Error Handler Middleware
     3→ *
     4→ * Centralized error handling for all API errors.
     5→ * Maps MMS error classes to appropriate HTTP status codes and response formats.
     6→ *
     7→ * @see specs/005-api.md for error response format
     8→ */
     9→
    10→import type { Context, ErrorHandler, NotFoundHandler } from 'hono';
    11→import { HTTPException } from 'hono/http-exception';
    12→import { error, ErrorCodes, type AppVariables } from '../types';
    13→import { logger } from '../../lib/logging/logger';
    14→import {
    15→  MmsError,
    16→  ValidationError,
    17→  NotFoundError,
    18→  ConflictError,
    19→  AuthenticationError,
    20→  AuthorizationError,
    21→  MaximoLockError,
    22→  ComplianceWindowError,
    23→  TrackConflictError,
    24→  MaterialConstraintError,
    25→  ServiceDemandViolationError,
    26→  DatabaseError,
    27→  ExternalServiceError,
    28→  ServiceUnavailableError,
    29→} from '../../lib/errors';
    30→
    31→/**
    32→ * Map MMS error to HTTP status code
    33→ */
    34→function getStatusCode(err: Error): number {
    35→  if (err instanceof HTTPException) {
    36→    return err.status;
    37→  }
    38→
    39→  if (err instanceof ValidationError) return 400;
    40→  if (err instanceof AuthenticationError) return 401;
    41→  if (err instanceof AuthorizationError) return 403;
    42→  if (err instanceof NotFoundError) return 404;
    43→  if (err instanceof ConflictError) return 409;
    44→  if (err instanceof MaximoLockError) return 409;
    45→  if (err instanceof ComplianceWindowError) return 422;
    46→  if (err instanceof TrackConflictError) return 422;
    47→  if (err instanceof MaterialConstraintError) return 422;
    48→  if (err instanceof ServiceDemandViolationError) return 422;
    49→  if (err instanceof ServiceUnavailableError) return 503;
    50→  if (err instanceof DatabaseError) return 503;
    51→  if (err instanceof ExternalServiceError) return 502;
    52→  if (err instanceof MmsError) return err.statusCode || 500;
    53→
    54→  return 500;
    55→}
    56→
    57→/**
    58→ * Map MMS error to error code
    59→ */
    60→function getErrorCode(err: Error): string {
    61→  if (err instanceof HTTPException) {
    62→    if (err.status === 401) return ErrorCodes.UNAUTHORIZED;
    63→    if (err.status === 403) return ErrorCodes.FORBIDDEN;
    64→    if (err.status === 404) return ErrorCodes.NOT_FOUND;
    65→    if (err.status === 429) return ErrorCodes.RATE_LIMITED;
    66→    return ErrorCodes.INTERNAL_ERROR;
    67→  }
    68→
    69→  if (err instanceof ValidationError) return ErrorCodes.VALIDATION_ERROR;
    70→  if (err instanceof AuthenticationError) return ErrorCodes.UNAUTHORIZED;
    71→  if (err instanceof AuthorizationError) return ErrorCodes.FORBIDDEN;
    72→  if (err instanceof NotFoundError) return ErrorCodes.NOT_FOUND;
    73→  if (err instanceof ConflictError) return ErrorCodes.CONFLICT;
    74→  if (err instanceof MaximoLockError) return ErrorCodes.MAXIMO_LOCK;
    75→  if (err instanceof ComplianceWindowError) return ErrorCodes.OUTSIDE_WINDOW;
    76→  if (err instanceof TrackConflictError) return ErrorCodes.TRACK_CONFLICT;
    77→  if (err instanceof MaterialConstraintError) return ErrorCodes.MATERIAL_BLOCK;
    78→  if (err instanceof ServiceDemandViolationError) return ErrorCodes.SERVICE_DEMAND_VIOLATION;
    79→  if (err instanceof ServiceUnavailableError) return ErrorCodes.SERVICE_UNAVAILABLE;
    80→  if (err instanceof DatabaseError) return ErrorCodes.DATABASE_ERROR;
    81→  if (err instanceof ExternalServiceError) return ErrorCodes.EXTERNAL_SERVICE_ERROR;
    82→  if (err instanceof MmsError) return err.code;
    83→
    84→  return ErrorCodes.INTERNAL_ERROR;
    85→}
    86→
    87→/**
    88→ * Get error details for response
    89→ */
    90→function getErrorDetails(err: Error): unknown {
    91→  if (err instanceof ValidationError) {
    92→    return {
    93→      field: err.field,
    94→      errors: err.errors,
    95→    };
    96→  }
    97→
    98→  if (err instanceof MmsError && err.context) {
    99→    return err.context;
   100→  }
   101→
   102→  return undefined;
   103→}
   104→
   105→/**
   106→ * Create error handler for Hono app
   107→ */
   108→export function createErrorHandler(): ErrorHandler<{ Variables: AppVariables }> {
   109→  return (err: Error, c: Context<{ Variables: AppVariables }>) => {
   110→    const requestId = c.get('requestId') || 'unknown';
   111→    const statusCode = getStatusCode(err);
   112→    const errorCode = getErrorCode(err);
   113→    const details = getErrorDetails(err);
   114→
   115→    // Log error with context
   116→    const logData = {
   117→      requestId,
   118→      method: c.req.method,
   119→      path: c.req.path,
   120→      statusCode,
   121→      errorCode,
   122→      error: err.message,
   123→      stack: statusCode >= 500 ? err.stack : undefined,
   124→    };
   125→
   126→    if (statusCode >= 500) {
   127→      logger.error(logData, 'Request failed with server error');
   128→    } else if (statusCode >= 400) {
   129→      logger.warn(logData, 'Request failed with client error');
   130→    }
   131→
   132→    return c.json(error(errorCode, err.message, requestId, details), statusCode as 400);
   133→  };
   134→}
   135→
   136→/**
   137→ * Not found handler for undefined routes
