     1→     1→/**
     2→     2→ * Authentication Routes
     3→     3→ *
     4→     4→ * REST endpoints for user authentication and session management.
     5→     5→ * Implements JWT-based authentication per spec 005.2.
     6→     6→ *
     7→     7→ * Endpoints:
     8→     8→ * - POST /auth/login - Authenticate user and obtain tokens
     9→     9→ * - POST /auth/refresh - Refresh access token
    10→    10→ * - POST /auth/logout - Invalidate session
    11→    11→ *
    12→    12→ * @see specs/005-api.md Section 5.2
    13→    13→ */
    14→    14→
    15→    15→import { Hono } from 'hono';
    16→    16→import {
    17→    17→  success,
    18→    18→  error,
    19→    19→  ErrorCodes,
    20→    20→  type AppVariables,
    21→    21→} from '../types';
    22→    22→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    23→    23→import {
    24→    24→  getAuthService,
    25→    25→  type LoginRequest,
    26→    26→  type RefreshRequest,
    27→    27→} from '../../services/auth';
    28→    28→import { validateLoginRequest } from '../../lib/schemas';
    29→    29→import {
    30→    30→  AuthenticationError,
    31→    31→  TokenExpiredError,
    32→    32→  InvalidTokenError,
    33→    33→  isMmsError,
    34→    34→} from '../../lib/errors';
    35→    35→
    36→    36→// Singleton service instance
    37→    37→let authService: ReturnType<typeof getAuthService> | null = null;
    38→    38→
    39→    39→function getService(): ReturnType<typeof getAuthService> {
    40→    40→  if (!authService) {
    41→    41→    authService = getAuthService();
    42→    42→  }
    43→    43→  return authService;
    44→    44→}
    45→    45→
    46→    46→export const authRoutes = new Hono<{ Variables: AppVariables }>();
    47→    47→
    48→    48→/**
    49→    49→ * POST /auth/login
    50→    50→ *
    51→    51→ * Authenticate user with email and password.
    52→    52→ * Returns access token, refresh token, and user information.
    53→    53→ */
    54→    54→authRoutes.post('/auth/login', async (c) => {
    55→    55→  const service = getService();
    56→    56→  const requestId = getRequestId(c);
    57→    57→
    58→    58→  try {
    59→    59→    // Parse request body
    60→    60→    const body = await c.req.json();
    61→    61→
    62→    62→    // Validate login request
    63→    63→    const validation = validateLoginRequest(body);
    64→    64→    if (!validation.valid) {
    65→    65→      return c.json(
    66→    66→        error(
    67→    67→          ErrorCodes.VALIDATION_ERROR,
    68→    68→          'Invalid login request',
    69→    69→          requestId,
    70→    70→          { errors: validation.errors }
    71→    71→        ),
    72→    72→        400 as const
    73→    73→      );
    74→    74→    }
    75→    75→
    76→    76→    // Get client info for session tracking
    77→    77→    const ipAddress = c.req.header('x-forwarded-for')?.split(',')[0]?.trim() ||
    78→    78→                      c.req.header('x-real-ip') ||
    79→    79→                      'unknown';
    80→    80→    const userAgent = c.req.header('user-agent') || 'unknown';
    81→    81→
    82→    82→    // Perform login
    83→    83→    const loginRequest: LoginRequest = {
    84→    84→      email: body.email,
    85→    85→      password: body.password,
    86→    86→      ipAddress,
    87→    87→      userAgent,
    88→    88→    };
    89→    89→
    90→    90→    const result = await service.login(loginRequest);
    91→    91→
    92→    92→    return c.json(
    93→    93→      success(result, {
    94→    94→        timing: { durationMs: getRequestDuration(c) },
    95→    95→      })
    96→    96→    );
    97→    97→  } catch (err) {
    98→    98→    if (err instanceof AuthenticationError) {
    99→    99→      return c.json(
   100→   100→        error(ErrorCodes.UNAUTHORIZED, err.message, requestId),
   101→   101→        401 as const
   102→   102→      );
   103→   103→    }
   104→   104→
   105→   105→    if (isMmsError(err)) {
   106→   106→      return c.json(
   107→   107→        error(err.code, err.message, requestId),
   108→   108→        err.statusCode as 400 | 401 | 403 | 404 | 409 | 422 | 500 | 502 | 503 | 504
   109→   109→      );
   110→   110→    }
   111→   111→
   112→   112→    throw err;
   113→   113→  }
   114→   114→});
   115→   115→
   116→   116→/**
   117→   117→ * POST /auth/refresh
   118→   118→ *
   119→   119→ * Refresh access token using refresh token.
   120→   120→ * Implements token rotation for security.
   121→   121→ */
   122→   122→authRoutes.post('/auth/refresh', async (c) => {
   123→   123→  const service = getService();
   124→   124→  const requestId = getRequestId(c);
   125→   125→
   126→   126→  try {
   127→   127→    // Parse request body
   128→   128→    const body = await c.req.json();
   129→   129→
   130→   130→    // Validate refresh token is provided
   131→   131→    if (!body.refreshToken || typeof body.refreshToken !== 'string') {
   132→   132→      return c.json(
   133→   133→        error(
   134→   134→          ErrorCodes.VALIDATION_ERROR,
   135→   135→          'Refresh token is required',
   136→   136→          requestId
   137→   137→        ),
   138→   138→        400 as const
   139→   139→      );
   140→   140→    }
   141→   141→
   142→   142→    // Get client info
   143→   143→    const ipAddress = c.req.header('x-forwarded-for')?.split(',')[0]?.trim() ||
   144→   144→                      c.req.header('x-real-ip') ||
   145→   145→                      'unknown';
   146→   146→    const userAgent = c.req.header('user-agent') || 'unknown';
   147→   147→
   148→   148→    // Perform token refresh
   149→   149→    const refreshRequest: RefreshRequest = {
   150→   150→      refreshToken: body.refreshToken,
   151→   151→      ipAddress,
   152→   152→      userAgent,
   153→   153→    };
   154→   154→
   155→   155→    const result = await service.refreshToken(refreshRequest);
   156→   156→
   157→   157→    return c.json(
   158→   158→      success(result, {
   159→   159→        timing: { durationMs: getRequestDuration(c) },
   160→   160→      })
   161→   161→    );
   162→   162→  } catch (err) {
   163→   163→    if (err instanceof TokenExpiredError) {
   164→   164→      return c.json(
   165→   165→        error(ErrorCodes.UNAUTHORIZED, 'Refresh token has expired', requestId),
   166→   166→        401 as const
   167→   167→      );
   168→   168→    }
   169→   169→
   170→   170→    if (err instanceof InvalidTokenError) {
   171→   171→      return c.json(
   172→   172→        error(ErrorCodes.UNAUTHORIZED, err.message, requestId),
   173→   173→        401 as const
   174→   174→      );
   175→   175→    }
   176→   176→
   177→   177→    if (isMmsError(err)) {
   178→   178→      return c.json(
   179→   179→        error(err.code, err.message, requestId),
   180→   180→        err.statusCode as 400 | 401 | 403 | 404 | 409 | 422 | 500 | 502 | 503 | 504
   181→   181→      );
   182→   182→    }
   183→   183→
   184→   184→    throw err;
   185→   185→  }
   186→   186→});
   187→   187→
   188→   188→/**
   189→   189→ * POST /auth/logout
   190→   190→ *
   191→   191→ * Invalidate current session.
   192→   192→ * Requires Authorization header with Bearer token.
   193→   193→ */
   194→   194→authRoutes.post('/auth/logout', async (c) => {
   195→   195→  const service = getService();
   196→   196→  const requestId = getRequestId(c);
   197→   197→
   198→   198→  try {
   199→   199→    // Extract token from Authorization header
   200→   200→    const authHeader = c.req.header('authorization');
   201→   201→    if (!authHeader || !authHeader.startsWith('Bearer ')) {
   202→   202→      return c.json(
   203→   203→        error(
   204→   204→          ErrorCodes.UNAUTHORIZED,
   205→   205→          'Authorization header with Bearer token is required',
   206→   206→          requestId
   207→   207→        ),
   208→   208→        401 as const
   209→   209→      );
   210→   210→    }
   211→   211→
   212→   212→    const token = authHeader.substring(7); // Remove 'Bearer ' prefix
   213→   213→
   214→   214→    // Perform logout
   215→   215→    await service.logout(token);
   216→   216→
   217→   217→    return c.json(
   218→   218→      success({ message: 'Logged out successfully' }, {
   219→   219→        timing: { durationMs: getRequestDuration(c) },
   220→   220→      })
   221→   221→    );
   222→   222→  } catch (err) {
   223→   223→    if (err instanceof InvalidTokenError) {
   224→   224→      return c.json(
   225→   225→        error(ErrorCodes.UNAUTHORIZED, err.message, requestId),
   226→   226→        401 as const
   227→   227→      );
   228→   228→    }
   229→   229→
   230→   230→    if (isMmsError(err)) {
   231→   231→      return c.json(
   232→   232→        error(err.code, err.message, requestId),
   233→   233→        err.statusCode as 400 | 401 | 403 | 404 | 409 | 422 | 500 | 502 | 503 | 504
   234→   234→      );
   235→   235→    }
   236→   236→
   237→   237→    throw err;
   238→   238→  }
   239→   239→});
   240→   240→
   241→   241→/**
   242→   242→ * GET /auth/me
   243→   243→ *
   244→   244→ * Get current authenticated user information.
   245→   245→ * Requires Authorization header with Bearer token.
   246→   246→ * Note: This is a convenience endpoint not in the original spec.
   247→   247→ */
   248→   248→authRoutes.get('/auth/me', async (c) => {
   249→   249→  const service = getService();
   250→   250→  const requestId = getRequestId(c);
   251→   251→
   252→   252→  try {
   253→   253→    // Extract token from Authorization header
   254→   254→    const authHeader = c.req.header('authorization');
   255→   255→    if (!authHeader || !authHeader.startsWith('Bearer ')) {
   256→   256→      return c.json(
   257→   257→        error(
   258→   258→          ErrorCodes.UNAUTHORIZED,
   259→   259→          'Authorization header with Bearer token is required',
   260→   260→          requestId
   261→   261→        ),
   262→   262→        401 as const
   263→   263→      );
   264→   264→    }
   265→   265→
   266→   266→    const token = authHeader.substring(7);
   267→   267→
   268→   268→    // Verify token and get session data
   269→   269→    const session = await service.verifyAccessToken(token);
   270→   270→
   271→   271→    // Get full user data
   272→   272→    const user = await service.getUserById(session.userId);
   273→   273→
   274→   274→    if (!user) {
   275→   275→      return c.json(
   276→   276→        error(ErrorCodes.NOT_FOUND, 'User not found', requestId),
   277→   277→        404 as const
   278→   278→      );
   279→   279→    }
   280→   280→
   281→   281→    return c.json(
   282→   282→      success(user, {
   283→   283→        timing: { durationMs: getRequestDuration(c) },
   284→   284→      })
   285→   285→    );
   286→   286→  } catch (err) {
   287→   287→    if (err instanceof TokenExpiredError) {
   288→   288→      return c.json(
   289→   289→        error(ErrorCodes.UNAUTHORIZED, 'Access token has expired', requestId),
   290→   290→        401 as const
   291→   291→      );
   292→   292→    }
   293→   293→
   294→   294→    if (err instanceof InvalidTokenError) {
   295→   295→      return c.json(
   296→   296→        error(ErrorCodes.UNAUTHORIZED, err.message, requestId),
   297→   297→        401 as const
   298→   298→      );
   299→   299→    }
   300→   300→
   301→   301→    if (isMmsError(err)) {
   302→   302→      return c.json(
   303→   303→        error(err.code, err.message, requestId),
   304→   304→        err.statusCode as 400 | 401 | 403 | 404 | 409 | 422 | 500 | 502 | 503 | 504
   305→   305→      );
   306→   306→    }
   307→   307→
   308→   308→    throw err;
   309→   309→  }
   310→   310→});
