   215→/**
   216→ * GET /trains/:id
   217→ *
   218→ * Get detailed train information.
   219→ */
   220→fleetRoutes.get('/trains/:id', async (c) => {
   221→  const requestId = getRequestId(c);
   222→  const trainId = c.req.param('id');
   223→
   224→  if (!isValidUuid(trainId)) {
