   262→            code: trainWithDetails.homeDepot.code,
   263→            name: trainWithDetails.homeDepot.name,
   264→          }
   265→        : null,
   266→      commissioningDate: trainWithDetails.commissioningDate,
   267→      isActive: trainWithDetails.active,
   268→    })
   269→  );
   270→});
   271→
   272→/**
   273→ * PATCH /trains/:id
   274→ *
