    61→    61→ */
    62→    62→pmScheduleRoutes.get('/pm/schedule', async (c) => {
    63→    63→  // Parse query filters
    64→    64→  const trainId = c.req.query('trainId');
    65→    65→  const depotId = c.req.query('depotId');
    66→    66→  const pmTypeId = c.req.query('pmTypeId');
