   109→   109→    sort: c.req.query('sort'),
   110→   110→  });
   111→   111→
   112→   112→  // Count total items
   113→   113→  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
   114→   114→  const totalResult = await db
