   365→   365→ */
   366→   366→pmScheduleRoutes.patch('/pm/schedule/:id', async (c) => {
   367→   367→  const requestId = getRequestId(c);
   368→   368→  const pmId = c.req.param('id');
   369→   369→
   370→   370→  if (!isValidUuid(pmId)) {
   371→   371→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   372→   372→  }
   373→   373→
   374→   374→  const body = await c.req.json();
   375→   375→
   376→   376→  // Validate reason is provided
   377→   377→  if (!body.reason || typeof body.reason !== 'string' || body.reason.trim().length === 0) {
   378→   378→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'reason is required for PM changes', requestId), 400);
   379→   379→  }
   380→   380→
   381→   381→  // Validate targetDate if provided
   382→   382→  if (body.targetDate && !/^\d{4}-\d{2}-\d{2}$/.test(body.targetDate)) {
   383→   383→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'targetDate must be in YYYY-MM-DD format', requestId), 400);
   384→   384→  }
   385→   385→
   386→   386→  // Validate assignedTrackId if provided
   387→   387→  if (body.assignedTrackId && !isValidUuid(body.assignedTrackId)) {
   388→   388→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'assignedTrackId must be a valid UUID', requestId), 400);
   389→   389→  }
