   408→   408→  };
   409→   409→
   410→   410→  const updated = await service.movePm(request);
   411→   411→
   412→   412→  // Calculate impact assessment
   413→   413→  const impactAssessment = {
   414→   414→    complianceStatus: updated.targetDate >= updated.constraintStart && updated.targetDate <= updated.constraintEnd
   415→   415→      ? 'WITHIN_WINDOW'
   416→   416→      : 'OUTSIDE_WINDOW',
   417→   417→    manhourImpact: 0, // TODO: Calculate actual impact
   418→   418→    conflictsCreated: 0, // TODO: Check for new conflicts
   419→   419→  };
   420→   420→
   421→   421→  // Broadcast PM update to all connected canvas subscribers
   422→   422→  const hub = getWebSocketHub();
   423→   423→  hub.broadcastPmUpdated({
   424→   424→    pmId: updated.id,
   425→   425→    trainId: updated.trainId,
   426→   426→    trainNumber: currentPm.train?.trainNumber ?? 'Unknown',
   427→   427→    changes: [
   428→   428→      { field: 'targetDate', oldValue: currentPm.targetDate, newValue: updated.targetDate },
   429→   429→      ...(body.assignedTrackId && body.assignedTrackId !== currentPm.assignedTrackId
   430→   430→        ? [{ field: 'assignedTrackId', oldValue: currentPm.assignedTrackId, newValue: body.assignedTrackId }]
   431→   431→        : []),
   432→   432→    ],
   433→   433→    changedBy: {
   434→   434→      userId: user?.id ?? 'system',
   435→   435→      displayName: user?.email ?? 'System',
   436→   436→    },
   437→   437→  });
   438→   438→
   439→   439→  return c.json(
   440→   440→    success({
   441→   441→      id: updated.id,
   442→   442→      targetDate: updated.targetDate,
   443→   443→      previousTargetDate: currentPm.targetDate,
   444→   444→      assignedTrackId: updated.assignedTrackId,
   445→   445→      previousTrackId: currentPm.assignedTrackId,
   446→   446→      updatedAt: updated.updatedAt,
   447→   447→      updatedBy: user?.id,
   448→   448→      explanation: {
   449→   449→        changeType: 'DATE_CHANGED',
   450→   450→        reason: body.reason,
   451→   451→        impactAssessment,
   452→   452→      },
   453→   453→    })
   454→   454→  );
   455→   455→});
