     1→     1→/**
     2→     2→ * Optimizer Routes
     3→     3→ *
     4→     4→ * REST endpoints for triggering and monitoring optimization jobs.
     5→     5→ * Jobs are processed asynchronously via BullMQ workers.
     6→     6→ *
     7→     7→ * Endpoints:
     8→     8→ * - POST /optimizer/run-assignment - Trigger train-to-route assignment optimization
     9→     9→ * - GET /optimizer/jobs/:jobId - Get job status and results
    10→    10→ * - POST /optimizer/tactical-schedule - Trigger tactical PM scheduling (12-week)
    11→    11→ * - POST /optimizer/strategic-plan - Trigger strategic planning (10-year)
    12→    12→ *
    13→    13→ * @see specs/005-api.md Section 5.6
    14→    14→ */
    15→    15→
    16→    16→import { Hono } from 'hono';
    17→    17→import {
    18→    18→  success,
    19→    19→  error,
    20→    20→  ErrorCodes,
    21→    21→  type AppVariables,
    22→    22→} from '../types';
    23→    23→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    24→    24→import { isValidUuid } from '../../lib/schemas';
    25→    25→import {
    26→    26→  addJob,
    27→    27→  getQueue,
    28→    28→  QUEUE_NAMES,
    29→    29→  type OptimizerJobData,
    30→    30→  type TacticalSchedulerJobData,
    31→    31→  type StrategicPlannerJobData,
    32→    32→} from '../../lib/queue';
    33→    33→
    34→    34→export const optimizerRoutes = new Hono<{ Variables: AppVariables }>();
    35→    35→
    36→    36→// =============================================================================
    37→    37→// Types
    38→    38→// =============================================================================
    39→    39→
    40→    40→/**
    41→    41→ * Request body for POST /optimizer/run-assignment
    42→    42→ */
    43→    43→interface RunAssignmentRequest {
    44→    44→  date: string; // ISO date string (YYYY-MM-DD)
    45→    45→  fleetId: string;
    46→    46→  depotId?: string;
    47→    47→  options?: {
    48→    48→    maxSolveTimeSeconds?: number;
    49→    49→    explanationVerbosity?: 'MINIMAL' | 'STANDARD' | 'DETAILED';
    50→    50→  };
    51→    51→  constraints?: {
    52→    52→    serviceRequirements?: Record<string, number>;
    53→    53→    unavailableTrains?: string[];
    54→    54→    preferredAssignments?: Record<string, string>;
    55→    55→  };
    56→    56→}
    57→    57→
    58→    58→/**
    59→    59→ * Request body for POST /optimizer/tactical-schedule
    60→    60→ */
    61→    61→interface TacticalScheduleRequest {
    62→    62→  depotId?: string;
    63→    63→  fleetId?: string;
    64→    64→  trainIds?: string[];
    65→    65→  horizonWeeks?: number; // Default 12
    66→    66→  dryRun?: boolean;
    67→    67→}
    68→    68→
    69→    69→/**
    70→    70→ * Request body for POST /optimizer/strategic-plan
    71→    71→ */
    72→    72→interface StrategicPlanRequest {
    73→    73→  horizonYears?: number; // Default 10
    74→    74→  fromBaselineId?: string;
    75→    75→  fleetId?: string;
    76→    76→  populationSize?: number;
    77→    77→  generations?: number;
    78→    78→}
    79→    79→
    80→    80→/**
    81→    81→ * Optimizer job status response
    82→    82→ */
    83→    83→type OptimizerJobStatus =
    84→    84→  | 'waiting'
    85→    85→  | 'active'
    86→    86→  | 'completed'
    87→    87→  | 'failed'
    88→    88→  | 'delayed'
    89→    89→  | 'unknown';
    90→    90→
    91→    91→// =============================================================================
    92→    92→// Helper Functions
    93→    93→// =============================================================================
    94→    94→
    95→    95→/**
    96→    96→ * Validate ISO date string (YYYY-MM-DD)
    97→    97→ */
    98→    98→function isValidDateString(date: string): boolean {
    99→    99→  if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
   100→   100→    return false;
   101→   101→  }
   102→   102→  const parsed = new Date(date);
   103→   103→  return !isNaN(parsed.getTime());
   104→   104→}
   105→   105→
   106→   106→/**
   107→   107→ * Get detailed job information including result
   108→   108→ */
   109→   109→async function getDetailedJob(
   110→   110→  queueName: typeof QUEUE_NAMES[keyof typeof QUEUE_NAMES],
   111→   111→  jobId: string
   112→   112→): Promise<{
   113→   113→  id: string;
   114→   114→  status: OptimizerJobStatus;
   115→   115→  progress?: unknown;
   116→   116→  result?: unknown;
   117→   117→  failedReason?: string;
   118→   118→  startedAt?: string;
   119→   119→  completedAt?: string;
   120→   120→  attemptsMade?: number;
   121→   121→} | null> {
   122→   122→  const queue = getQueue(queueName);
   123→   123→  const job = await queue.getJob(jobId);
   124→   124→
   125→   125→  if (!job) return null;
   126→   126→
   127→   127→  const state = await job.getState();
   128→   128→  const result = job.returnvalue;
   129→   129→  const failedReason = job.failedReason;
   130→   130→  const progress = job.progress;
   131→   131→  const processedOn = job.processedOn;
   132→   132→  const finishedOn = job.finishedOn;
   133→   133→
   134→   134→  return {
   135→   135→    id: job.id!,
   136→   136→    status: (state as OptimizerJobStatus) || 'unknown',
   137→   137→    ...(progress !== undefined && { progress }),
   138→   138→    ...(result !== undefined && { result }),
   139→   139→    ...(failedReason && { failedReason }),
   140→   140→    ...(processedOn && { startedAt: new Date(processedOn).toISOString() }),
   141→   141→    ...(finishedOn && { completedAt: new Date(finishedOn).toISOString() }),
   142→   142→    attemptsMade: job.attemptsMade,
   143→   143→  };
   144→   144→}
   145→   145→
   146→   146→/**
   147→   147→ * Estimate completion time based on job complexity
   148→   148→ */
   149→   149→function estimateCompletionSeconds(trainCount: number, routeCount: number): number {
   150→   150→  // Rough estimate: base time + scaling factor
   151→   151→  const baseTime = 10;
   152→   152→  const scaleFactor = 0.5;
   153→   153→  return Math.ceil(baseTime + (trainCount * routeCount * scaleFactor) / 1000);
   154→   154→}
   155→   155→
   156→   156→// =============================================================================
   157→   157→// Routes
   158→   158→// =============================================================================
   159→   159→
   160→   160→/**
   161→   161→ * POST /optimizer/run-assignment
   162→   162→ *
   163→   163→ * Trigger run assignment optimization for a specific date and fleet.
   164→   164→ * The optimization is performed asynchronously and returns a job ID
   165→   165→ * that can be used to check status and retrieve results.
   166→   166→ */
   167→   167→optimizerRoutes.post('/optimizer/run-assignment', async (c) => {
   168→   168→  const requestId = getRequestId(c);
   169→   169→
   170→   170→  // Parse request body
   171→   171→  let body: RunAssignmentRequest;
   172→   172→  try {
   173→   173→    body = await c.req.json();
   174→   174→  } catch {
   175→   175→    return c.json(
   176→   176→      error(ErrorCodes.VALIDATION_ERROR, 'Invalid JSON body', requestId),
   177→   177→      400
   178→   178→    );
   179→   179→  }
   180→   180→
   181→   181→  // Validate required fields
   182→   182→  if (!body.date) {
   183→   183→    return c.json(
   184→   184→      error(ErrorCodes.VALIDATION_ERROR, 'date is required', requestId, {
   185→   185→        field: 'date',
   186→   186→      }),
   187→   187→      400
   188→   188→    );
   189→   189→  }
   190→   190→
   191→   191→  if (!isValidDateString(body.date)) {
   192→   192→    return c.json(
   193→   193→      error(
   194→   194→        ErrorCodes.VALIDATION_ERROR,
   195→   195→        'Invalid date format. Expected YYYY-MM-DD',
   196→   196→        requestId,
   197→   197→        { field: 'date', value: body.date }
   198→   198→      ),
   199→   199→      400
   200→   200→    );
   201→   201→  }
   202→   202→
   203→   203→  if (!body.fleetId) {
   204→   204→    return c.json(
   205→   205→      error(ErrorCodes.VALIDATION_ERROR, 'fleetId is required', requestId, {
   206→   206→        field: 'fleetId',
   207→   207→      }),
   208→   208→      400
   209→   209→    );
   210→   210→  }
   211→   211→
   212→   212→  if (!isValidUuid(body.fleetId)) {
   213→   213→    return c.json(
   214→   214→      error(
   215→   215→        ErrorCodes.VALIDATION_ERROR,
   216→   216→        'Invalid fleetId format. Expected UUID',
   217→   217→        requestId,
   218→   218→        { field: 'fleetId', value: body.fleetId }
   219→   219→      ),
   220→   220→      400
   221→   221→    );
   222→   222→  }
   223→   223→
   224→   224→  // Validate options if provided
   225→   225→  const maxSolveTimeSeconds = body.options?.maxSolveTimeSeconds ?? 30;
   226→   226→  if (maxSolveTimeSeconds < 1 || maxSolveTimeSeconds > 300) {
   227→   227→    return c.json(
   228→   228→      error(
   229→   229→        ErrorCodes.VALIDATION_ERROR,
   230→   230→        'maxSolveTimeSeconds must be between 1 and 300',
   231→   231→        requestId,
   232→   232→        { field: 'options.maxSolveTimeSeconds', value: maxSolveTimeSeconds }
   233→   233→      ),
   234→   234→      400
   235→   235→    );
   236→   236→  }
   237→   237→
   238→   238→  const validVerbosityLevels = ['MINIMAL', 'STANDARD', 'DETAILED'];
   239→   239→  const verbosity = body.options?.explanationVerbosity ?? 'STANDARD';
   240→   240→  if (!validVerbosityLevels.includes(verbosity)) {
   241→   241→    return c.json(
   242→   242→      error(
   243→   243→        ErrorCodes.VALIDATION_ERROR,
   244→   244→        `explanationVerbosity must be one of: ${validVerbosityLevels.join(', ')}`,
   245→   245→        requestId,
   246→   246→        { field: 'options.explanationVerbosity', value: verbosity }
   247→   247→      ),
   248→   248→      400
   249→   249→    );
   250→   250→  }
   251→   251→
   252→   252→  // Build job data
   253→   253→  const jobData: OptimizerJobData = {
   254→   254→    date: body.date,
