   267→   267→    }
   268→   268→  );
   269→   269→
   270→   270→  // Estimate completion time (this would be more accurate with fleet size info)
   271→   271→  const estimatedCompletionSeconds = estimateCompletionSeconds(50, 10);
   272→   272→
   273→   273→  return c.json(
   274→   274→    success(
   275→   275→      {
