   282→   282→      }
   283→   283→    ),
   284→   284→    202
   285→   285→  );
   286→   286→});
   287→   287→
   288→   288→/**
   289→   289→ * GET /optimizer/jobs/:jobId
   290→   290→ *
   291→   291→ * Get the status and results of an optimizer job.
   292→   292→ */
   293→   293→optimizerRoutes.get('/optimizer/jobs/:jobId', async (c) => {
   294→   294→  const requestId = getRequestId(c);
   295→   295→  const jobId = c.req.param('jobId');
