   321→   321→    active: 'PROCESSING',
   322→   322→    completed: 'COMPLETED',
   323→   323→    failed: 'FAILED',
   324→   324→  };
   325→   325→
   326→   326→  const apiStatus = statusMap[job.status] || 'UNKNOWN';
   327→   327→
   328→   328→  // Build response based on job status
   329→   329→  interface JobResponse {
