   363→   363→      attemptsMade: job.attemptsMade,
   364→   364→    };
   365→   365→  }
   366→   366→
   367→   367→  return c.json(
   368→   368→    success(response, {
   369→   369→      timing: { durationMs: getRequestDuration(c) },
   370→   370→    })
   371→   371→  );
   372→   372→});
