     1→     1→/**
     2→     2→ * Man-hour Management Routes
     3→     3→ *
     4→     4→ * REST endpoints for man-hour projections and adjustment workflows.
     5→     5→ * Wraps ManHourLevelingService with HTTP interface per spec 005.7.
     6→     6→ *
     7→     7→ * Endpoints:
     8→     8→ * - GET /manhours/projections - List projections with filtering
     9→     9→ * - GET /manhours/adjustments - List proposed adjustments
    10→    10→ * - POST /manhours/adjustments/:id/approve - Approve an adjustment
    11→    11→ * - POST /manhours/adjustments/:id/reject - Reject an adjustment
    12→    12→ *
    13→    13→ * @see specs/005-api.md Section 5.7
    14→    14→ */
    15→    15→
    16→    16→import { Hono } from 'hono';
    17→    17→import { parseISO } from 'date-fns';
    18→    18→import {
    19→    19→  success,
