    34→    34→import { isValidUuid } from '../../lib/schemas';
    35→    35→
    36→    36→let manhourService: ReturnType<typeof getManHourLevelingService> | null = null;
    37→    37→
    38→    38→function getService(): ReturnType<typeof getManHourLevelingService> {
    39→    39→  if (!manhourService) {
    40→    40→    manhourService = getManHourLevelingService();
    41→    41→  }
    42→    42→  return manhourService;
    43→    43→}
    44→    44→
    45→    45→export const manhourRoutes = new Hono<{ Variables: AppVariables }>();
    46→    46→
    47→    47→/**
    48→    48→ * GET /manhours/projections
    49→    49→ *
    50→    50→ * Get man-hour projections with filtering.
    51→    51→ *
    52→    52→ * Query Parameters:
    53→    53→ * - depotId: Filter by depot
    54→    54→ * - fromDate: Period start (inclusive)
    55→    55→ * - toDate: Period end (inclusive)
    56→    56→ * - granularity: WEEKLY or MONTHLY
    57→    57→ * - projectionRunId: Filter by specific projection run
    58→    58→ */
    59→    59→manhourRoutes.get('/manhours/projections', async (c) => {
    60→    60→  const requestId = getRequestId(c);
    61→    61→
    62→    62→  // Parse query filters
    63→    63→  const depotId = c.req.query('depotId');
    64→    64→  const fromDate = c.req.query('fromDate');
    65→    65→  const toDate = c.req.query('toDate');
    66→    66→  const projectionRunId = c.req.query('projectionRunId');
    67→    67→
    68→    68→  // Validate UUIDs if provided
    69→    69→  if (depotId && !isValidUuid(depotId)) {
    70→    70→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'depotId must be a valid UUID', requestId), 400);
    71→    71→  }
    72→    72→  if (projectionRunId && !isValidUuid(projectionRunId)) {
    73→    73→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'projectionRunId must be a valid UUID', requestId), 400);
    74→    74→  }
    75→    75→
    76→    76→  // Validate date formats
    77→    77→  if (fromDate && !/^\d{4}-\d{2}-\d{2}$/.test(fromDate)) {
    78→    78→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'fromDate must be in YYYY-MM-DD format', requestId), 400);
    79→    79→  }
    80→    80→  if (toDate && !/^\d{4}-\d{2}-\d{2}$/.test(toDate)) {
    81→    81→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'toDate must be in YYYY-MM-DD format', requestId), 400);
    82→    82→  }
    83→    83→
    84→    84→  // Build filter object
    85→    85→  const filters: ProjectionFilters = {};
    86→    86→  if (depotId) filters.depotId = depotId;
    87→    87→  if (fromDate) filters.fromDate = parseISO(fromDate);
    88→    88→  if (toDate) filters.toDate = parseISO(toDate);
    89→    89→  if (projectionRunId) filters.projectionRunId = projectionRunId;
    90→    90→
    91→    91→  // Parse pagination
    92→    92→  const pagination = parsePaginationQuery({
    93→    93→    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
    94→    94→    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
    95→    95→    sort: c.req.query('sort'),
    96→    96→  });
    97→    97→
    98→    98→  const service = getService();
    99→    99→  const result = await service.getProjections(filters, pagination.page, pagination.pageSize);
   100→   100→
   101→   101→  // Map to API response format per spec 005.7
   102→   102→  const data = result.data.map((projection) => {
   103→   103→    const requiredTotal = parseFloat(projection.requiredTotalHours ?? '0');
   104→   104→    const availableTotal = parseFloat(projection.availableTotalHours ?? '0');
   105→   105→    const varianceHours = availableTotal - requiredTotal;
   106→   106→    const utilizationPct = availableTotal > 0 ? (requiredTotal / availableTotal) * 100 : 0;
   107→   107→
   108→   108→    return {
   109→   109→      depotId: projection.depotId,
   110→   110→      periodStart: projection.periodStart,
   111→   111→      periodEnd: projection.periodEnd,
   112→   112→      required: {
   113→   113→        pm: parseFloat(projection.requiredPmHours ?? '0'),
   114→   114→        corrective: parseFloat(projection.requiredCorrectiveHours ?? '0'),
   115→   115→        overhaul: parseFloat(projection.requiredOverhaulHours ?? '0'),
   116→   116→        total: requiredTotal,
   117→   117→      },
   118→   118→      available: {
   119→   119→        regular: parseFloat(projection.availableRegularHours ?? '0'),
   120→   120→        overtime: parseFloat(projection.availableOvertimeHours ?? '0'),
   121→   121→        total: availableTotal,
   122→   122→      },
   123→   123→      varianceHours,
   124→   124→      utilizationPct: Math.round(utilizationPct * 10) / 10,
   125→   125→      isOverloaded: requiredTotal > availableTotal,
   126→   126→      isUnderutilized: requiredTotal < availableTotal * 0.7,
   127→   127→      pendingAdjustments: 0, // TODO: Count adjustments when relation is loaded
   128→   128→    };
   129→   129→  });
   130→   130→
   131→   131→  return c.json(
   132→   132→    paginatedSuccess(
   133→   133→      data,
   134→   134→      {
   135→   135→        page: result.page,
   136→   136→        pageSize: result.pageSize,
   137→   137→        totalItems: result.total,
   138→   138→      },
   139→   139→      { durationMs: getRequestDuration(c) }
   140→   140→    )
   141→   141→  );
   142→   142→});
