   153→ * - toDate: Source period end (inclusive)
   154→ */
   155→manhourRoutes.get('/manhours/adjustments', async (c) => {
   156→  const requestId = getRequestId(c);
   157→
   158→  // Parse query filters
   159→  const status = c.req.query('status');
