   249→   249→      404
   250→   250→    );
   251→   251→  }
   252→   252→
   253→   253→  // Get trains requiring replan
   254→   254→  const trains = await service.getTrainsRequiringReplan();
   255→   255→
   256→   256→  // Get thresholds for severity calculation
   257→   257→  const thresholds = service.getThresholds();
   258→   258→
   259→   259→  // Map to response format
   260→   260→  const data = trains.map((drift) => ({
   261→   261→    trainId: drift.trainId,
