   264→   264→    actualKm: drift.actualKm,
   265→   265→    mileageDriftKm: drift.actualKm - drift.baselineProjectedKm,
   266→   266→    mileageDriftPct: drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
   267→   267→    avgPmDriftDays: drift.avgPmDriftDays ? parseFloat(drift.avgPmDriftDays) : 0,
   268→   268→    maxPmDriftDays: drift.maxPmDriftDays ?? 0,
   269→   269→    replanReason: drift.replanReason,
   270→   270→    driftSeverity: getDriftSeverity(
   271→   271→      drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
   272→   272→      drift.maxPmDriftDays ?? 0,
   273→   273→      true,
   274→   274→      thresholds
   275→   275→    ),
   276→   276→  }));
   277→   277→
   278→   278→  return c.json(
   279→   279→    success(
   280→   280→      {
   281→   281→        baselineId: baseline.id,
   282→   282→        baselineName: baseline.name,
   283→   283→        count: data.length,
   284→   284→        trains: data,
   285→   285→      },
   286→   286→      { timing: { durationMs: getRequestDuration(c) } }
   287→   287→    )
   288→   288→  );
   289→   289→});
