   454→   454→    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   455→   455→  });
   456→   456→
   457→   457→  // Get drift history
   458→   458→  const result = await service.getDriftHistory(filters, {
   459→   459→    page: pagination.page,
   460→   460→    pageSize: pagination.pageSize,
   461→   461→  });
   462→   462→
   463→   463→  // Map to API response format
