   470→   470→    actualKm: drift.actualKm,
   471→   471→    mileageDriftPct: drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
   472→   472→    avgPmDriftDays: drift.avgPmDriftDays ? parseFloat(drift.avgPmDriftDays) : 0,
   473→   473→    maxPmDriftDays: drift.maxPmDriftDays ?? 0,
   474→   474→    requiresReplan: drift.requiresReplan,
   475→   475→    replanReason: drift.replanReason,
   476→   476→    createdAt: drift.createdAt,
   477→   477→  }));
   478→   478→
   479→   479→  return c.json(
   480→   480→    paginatedSuccess(
   481→   481→      data,
   482→   482→      {
   483→   483→        page: result.page,
