   535→   535→    );
   536→   536→  }
   537→   537→
   538→   538→  return c.json(
   539→   539→    success(
   540→   540→      {
   541→   541→        status: 'completed',
   542→   542→        baselineId: result.baselineId,
   543→   543→        baselineVersion: result.baselineVersion,
   544→   544→        analysisDate: result.analysisDate,
   545→   545→        summary: result.summary,
   546→   546→        alertCount: result.alerts.length,
   547→   547→        alerts: result.alerts,
