   549→   549→      { timing: { durationMs: getRequestDuration(c) } }
   550→   550→    )
   551→   551→  );
   552→   552→});
   553→   553→
   554→   554→/**
   555→   555→ * GET /drift/train/:trainId
   556→   556→ *
