   586→   586→          mileageDriftPct: drift.mileageDriftPct ? parseFloat(drift.mileageDriftPct) : 0,
   587→   587→          avgPmDriftDays: drift.avgPmDriftDays ? parseFloat(drift.avgPmDriftDays) : 0,
   588→   588→          maxPmDriftDays: drift.maxPmDriftDays ?? 0,
   589→   589→          requiresReplan: drift.requiresReplan,
