   130→   130→  }));
   131→   131→
   132→   132→  return c.json(
   133→   133→    paginatedSuccess(
   134→   134→      scenarios,
   135→   135→      {
   136→   136→        page: result.page,
   137→   137→        pageSize: result.pageSize,
   138→   138→        totalItems: result.total,
   139→   139→      },
   140→   140→      { durationMs: getRequestDuration(c) }
   141→   141→    )
