   636→ * Promote a scenario to become the new production baseline.
   637→ * This will:
   638→ * 1. Materialize all scenario deltas
   639→ * 2. Create a new published baseline
   640→ * 3. Apply the deltas to the production PM schedule
   641→ * 4. Mark the scenario as PROMOTED
   642→ * 5. Supersede any previous published baseline
   643→ *
   644→ * Request body:
   645→ * - baselineName: Name for the new baseline (required)
   646→ * - description: Optional description
   647→ */
   648→scenarioRoutes.post('/scenarios/:id/promote', async (c) => {
   649→  const requestId = getRequestId(c);
   650→  const scenarioId = c.req.param('id');
   651→
   652→  if (!isValidUuid(scenarioId)) {
   653→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid scenario ID format', requestId), 400);
   654→  }
   655→
   656→  const body = await c.req.json();
   657→
   658→  // Validate required fields
   659→  if (!body.baselineName || typeof body.baselineName !== 'string' || body.baselineName.trim().length === 0) {
   660→    return c.json(
   661→      error(ErrorCodes.VALIDATION_ERROR, 'baselineName is required', requestId),
   662→      400
   663→    );
   664→  }
   665→
   666→  const userId = c.get('user')?.id ?? 'system';
   667→
   668→  const service = getService();
   669→  const baseline = await service.promoteToBaseline({
   670→    scenarioId,
   671→    baselineName: body.baselineName.trim(),
   672→    baselineDescription: body.description?.trim(),
   673→    userId,
   674→  });
