   676→  return c.json(
   677→    success(
   678→      {
   679→        promoted: true,
   680→        scenarioId,
   681→        baseline: {
   682→          id: baseline.id,
   683→          name: baseline.name,
   684→          version: baseline.version,
   685→          baselineDate: baseline.baselineDate,
   686→          status: baseline.status,
   687→          publishedAt: baseline.publishedAt,
   688→        },
   689→      },
   690→      { timing: { durationMs: getRequestDuration(c) } }
   691→    ),
   692→    201
